const assert = require('assert');
const DiContainer = require('../../../src/core/DiContainer');

describe('DiContainer (Unit)', () => {
  beforeEach(() => DiContainer.reset());

  it('should register and resolve a class', () => {
    class MyService {}
    DiContainer.register('MyService', MyService);

    const instance = DiContainer.resolve('MyService');
    assert.ok(instance instanceof MyService);
  });

  it('should throw if factory is missing', () => {
    assert.throws(() => DiContainer.resolve('Unknown'), /Keine Instanz oder Factory/);
  });

  it('should reuse resolved instance', () => {
    class Singleton {}
    DiContainer.register('Singleton', Singleton);

    const a = DiContainer.resolve('Singleton');
    const b = DiContainer.resolve('Singleton');
    assert.strictEqual(a, b);
  });

  it('should allow manual instance injection', () => {
    const obj = { name: 'manual' };
    DiContainer.set('Manual', obj);

    const resolved = DiContainer.resolve('Manual');
    assert.strictEqual(resolved.name, 'manual');
  });
});